class Solution {
public:
    int kIncreasing(vector<int>& arr, int k) {
        int operations = 0;
        for (int i = 0; i < arr.size(); i++) {
            for (int j = i + k; j < arr.size(); j++) {
                if (arr[j] < arr[i] && operations < arr.size() - i) {
                    arr[j] = arr[i];
                    operations++;
                }
            }
        }
        return operations;
    }
};
```

